// Build the Telegram HTML message for the owner's end-of-day recap.
// Endpoint already returns pre-formatted single-line summary strings; we
// just stack them under bold section headers.

const data = $input.first().json;

const esc = (s) => String(s ?? '无')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const lines = [
  `📊 <b>Incredibowl 当日复盘</b> — ${esc(data.today)}`,
  '',
  '🍱 <b>今日订单</b>',
  esc(data.todaySummary),
  '',
  '💳 <b>餐券销售</b>',
  esc(data.voucherSalesSummary),
  '',
  '👥 <b>今日客户</b>',
  esc(data.customerSummary),
  '',
  '📅 <b>明日预览</b>',
  esc(data.tomorrowSummary),
  '',
  '⚠️ <b>明日关键备注</b>',
  esc(data.tomorrowCriticalNotesText),
  '',
  '—— Incredibowl 自动复盘',
];

return [{ json: { text: lines.join('\n'), _raw: data } }];

const err = $input.first().json;
console.error('[daily-recap-tg] Telegram send failed', JSON.stringify(err));
return [{ json: { error: err } }];
